/*
 * Minimal HTMX-compatible shim for the local migration demo.
 *
 * Supported attributes:
 * - hx-get
 * - hx-post
 * - hx-target
 * - hx-swap="innerHTML|outerHTML"
 * - hx-encoding="multipart/form-data"
 * - hx-trigger="load|every Ns"
 *
 * This keeps the demo self-contained without pulling assets from a CDN.
 */
(function () {
  "use strict";

  var pollers = new WeakMap();

  function resolveTarget(element) {
    var selector = element.getAttribute("hx-target");
    return selector ? document.querySelector(selector) : element;
  }

  function swapContent(target, html, swapMode) {
    if (!target) {
      return;
    }
    if (swapMode === "outerHTML") {
      target.outerHTML = html;
    } else {
      target.innerHTML = html;
    }
  }

  function clearPoller(element) {
    var existing = pollers.get(element);
    if (existing) {
      window.clearInterval(existing);
      pollers.delete(element);
    }
  }

  function processNode(root) {
    if (!root || root.nodeType !== 1) {
      return;
    }
    bindElement(root);
    root.querySelectorAll("[hx-get], [hx-post]").forEach(bindElement);
  }

  async function issueRequest(element, method, sourceEvent) {
    var url = element.getAttribute(method === "GET" ? "hx-get" : "hx-post");
    if (!url) {
      return;
    }

    var target = resolveTarget(element);
    var swapMode = element.getAttribute("hx-swap") || "innerHTML";
    var requestClassElement = element.closest(".htmx-request") || element;
    var options = { method: method, headers: { "HX-Request": "true" } };

    if (method === "POST" && element.tagName === "FORM") {
      var encoding = element.getAttribute("hx-encoding");
      if (encoding === "multipart/form-data") {
        options.body = new FormData(element);
      } else {
        options.body = new URLSearchParams(new FormData(element));
        options.headers["Content-Type"] = "application/x-www-form-urlencoded; charset=UTF-8";
      }
    }

    if (method === "GET" && sourceEvent && sourceEvent.type === "submit") {
      options.body = new URLSearchParams(new FormData(element));
    }

    requestClassElement.classList.add("htmx-request");
    try {
      var response = await window.fetch(url, options);
      var html = await response.text();
      if (!response.ok) {
        throw new Error(html || ("Request failed with status " + response.status));
      }

      swapContent(target, html, swapMode);
      var nextRoot = swapMode === "outerHTML" ? resolveTarget(element) || document.body : target;
      processNode(nextRoot);
    } catch (error) {
      window.console.error("HTMX shim request failed", error);
    } finally {
      requestClassElement.classList.remove("htmx-request");
    }
  }

  function bindTrigger(element, method) {
    var trigger = element.getAttribute("hx-trigger");
    if (!trigger) {
      if (method === "POST" && element.tagName === "FORM") {
        element.addEventListener("submit", function (event) {
          event.preventDefault();
          issueRequest(element, method, event);
        });
      } else if (method === "GET" && element.tagName !== "FORM") {
        element.addEventListener("click", function (event) {
          event.preventDefault();
          issueRequest(element, method, event);
        });
      }
      return;
    }

    if (trigger === "load") {
      window.queueMicrotask(function () {
        issueRequest(element, method);
      });
      return;
    }

    var everyMatch = /^every\s+(\d+(?:\.\d+)?)s$/.exec(trigger);
    if (everyMatch) {
      clearPoller(element);
      var intervalMs = Number(everyMatch[1]) * 1000;
      var intervalId = window.setInterval(function () {
        if (!document.body.contains(element)) {
          clearPoller(element);
          return;
        }
        issueRequest(element, method);
      }, intervalMs);
      pollers.set(element, intervalId);
      return;
    }

    if (trigger === "submit") {
      element.addEventListener("submit", function (event) {
        event.preventDefault();
        issueRequest(element, method, event);
      });
    }
  }

  function bindElement(element) {
    if (element.__htmxShimBound) {
      return;
    }

    var method = null;
    if (element.hasAttribute("hx-post")) {
      method = "POST";
    } else if (element.hasAttribute("hx-get")) {
      method = "GET";
    }

    if (!method) {
      return;
    }

    element.__htmxShimBound = true;
    bindTrigger(element, method);
  }

  window.htmx = {
    process: processNode,
  };

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", function () {
      processNode(document.body);
    });
  } else {
    processNode(document.body);
  }
})();
